/**
 * Compliance Report Entity
 *
 * Snapshot report of compliance status for a framework in a given period.
 * Generated by ComplianceReportService for stakeholder communication.
 *
 * @see ComplianceReportService for report generation
 */

import { ComplianceFramework } from './ComplianceControl.entity';

export interface Finding {
  controlId: string;
  title: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
  description: string;
  recommendation: string;
}

export interface IComplianceReport {
  id: string;
  framework: ComplianceFramework;
  generatedAt: Date;
  periodStart: Date;
  periodEnd: Date;
  controlsTotal: number;
  controlsCompliant: number;
  controlsNonCompliant: number;
  compliancePercentage: number;
  findings: Finding[];
  recommendations: string[];
  approvedBy?: string;
  approvedAt?: Date;
}

/**
 * ComplianceReport entity class
 *
 * GIVEN: Compliance control assessment results
 * WHEN: Report generated
 * THEN: Summary stored for stakeholder reporting and audit trail
 *
 * Database: PostgreSQL table 'compliance_reports'
 */
export class ComplianceReport implements IComplianceReport {
  id: string;
  framework: ComplianceFramework;
  generatedAt: Date;
  periodStart: Date;
  periodEnd: Date;
  controlsTotal: number = 0;
  controlsCompliant: number = 0;
  controlsNonCompliant: number = 0;
  compliancePercentage: number = 0;
  findings: Finding[] = [];
  recommendations: string[] = [];
  approvedBy?: string;
  approvedAt?: Date;

  constructor(
    id: string,
    framework: ComplianceFramework,
    periodStart: Date,
    periodEnd: Date
  ) {
    this.id = id;
    this.framework = framework;
    this.generatedAt = new Date();
    this.periodStart = periodStart;
    this.periodEnd = periodEnd;
  }

  /**
   * Add finding
   */
  addFinding(finding: Finding): void {
    this.findings.push(finding);
  }

  /**
   * Add recommendation
   */
  addRecommendation(recommendation: string): void {
    this.recommendations.push(recommendation);
  }

  /**
   * Set control counts and calculate percentage
   */
  setControlResults(total: number, compliant: number): void {
    this.controlsTotal = total;
    this.controlsCompliant = compliant;
    this.controlsNonCompliant = total - compliant;
    this.compliancePercentage = total > 0 ? Math.round((compliant / total) * 100) : 0;
  }

  /**
   * Approve report
   */
  approve(approver: string): void {
    this.approvedBy = approver;
    this.approvedAt = new Date();
  }

  /**
   * Is approved?
   */
  isApproved(): boolean {
    return !!this.approvedBy && !!this.approvedAt;
  }

  /**
   * Validate report
   */
  validate(): boolean {
    if (!this.id || !this.framework) {
      throw new Error('Invalid report: required fields missing');
    }
    if (this.controlsTotal < 0 || this.controlsCompliant > this.controlsTotal) {
      throw new Error('Invalid report: control counts invalid');
    }
    return true;
  }

  /**
   * Export as JSON
   */
  toJSON(): Record<string, unknown> {
    return {
      id: this.id,
      framework: this.framework,
      generatedAt: this.generatedAt.toISOString(),
      periodStart: this.periodStart.toISOString(),
      periodEnd: this.periodEnd.toISOString(),
      controlsTotal: this.controlsTotal,
      controlsCompliant: this.controlsCompliant,
      controlsNonCompliant: this.controlsNonCompliant,
      compliancePercentage: this.compliancePercentage,
      findings: this.findings,
      recommendations: this.recommendations,
      approvedBy: this.approvedBy,
      approvedAt: this.approvedAt?.toISOString(),
    };
  }

  /**
   * Create from JSON
   */
  static fromJSON(data: Partial<ComplianceReport>): ComplianceReport {
    const report = new ComplianceReport(
      data.id || '',
      data.framework || ComplianceFramework.SOC2,
      data.periodStart || new Date(),
      data.periodEnd || new Date()
    );
    if (data.findings) report.findings = data.findings;
    if (data.recommendations) report.recommendations = data.recommendations;
    if (data.controlsTotal) {
      report.setControlResults(data.controlsTotal, data.controlsCompliant || 0);
    }
    if (data.approvedBy) report.approvedBy = data.approvedBy;
    if (data.approvedAt) report.approvedAt = new Date(data.approvedAt);
    return report;
  }
}
